1	/** In-memory task store with change subscription. */
2	
3	import { createTask, fetchTasks } from './api';
4	import type { Task } from './types';
5	
6	type Listener = (tasks: Task[]) => void;
7	
8	export class TaskStore {
9	  private tasks: Task[] = [];
10	  private listeners: Listener[] = [];
11	
12	  subscribe(listener: Listener): () => void {
13	    this.listeners.push(listener);
14	    return () => {
15	      this.listeners = this.listeners.filter((l) => l !== listener);
16	    };
17	  }
18	
19	  async refresh(status?: string): Promise<void> {
20	    this.tasks = await fetchTasks(status);
21	    this.emit();
22	  }
23	
24	  async add(title: string): Promise<void> {
25	    const task = await createTask(title);
26	    this.tasks = [...this.tasks, task];
27	    this.emit();
28	  }
29	
30	  all(): Task[] {
31	    return this.tasks;
32	  }
33	
34	  private emit(): void {
35	    for (const listener of this.listeners) {
36	      listener(this.tasks);
37	    }
38	  }
39	}
